/**
 * @name Path traversal in ResourceController via user-controlled path parameters
 * @description HTTP request path parameters flow to file system or classpath resource operations without adequate validation
 * @kind path-problem
 * @problem.severity error
 * @id java/resource-controller-traversal
 * @tags security
 *       external/cwe/cwe-022
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module ResourceTraversalConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
    or
    // Spring MVC path variables in ResourceController
    exists(Parameter p |
      p.getAnAnnotation().getType().hasQualifiedName("org.springframework.web.bind.annotation", "PathVariable") and
      source.asParameter() = p
    )
    or
    exists(Parameter p |
      p.getAnAnnotation().getType().hasQualifiedName("org.springframework.web.bind.annotation", "RequestParam") and
      source.asParameter() = p
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // ClassLoader.getResource / getResourceAsStream
    exists(MethodCall mc |
      mc.getMethod().hasName("getResource") or
      mc.getMethod().hasName("getResourceAsStream") |
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // ClassPathResource constructor
    exists(ClassInstanceExpr cie |
      cie.getConstructor().getDeclaringType().hasQualifiedName("org.springframework.core.io", "ClassPathResource") |
      sink.asExpr() = cie.getArgument(0)
    )
    or
    // FileSystemResource constructor
    exists(ClassInstanceExpr cie |
      cie.getConstructor().getDeclaringType().hasQualifiedName("org.springframework.core.io", "FileSystemResource") |
      sink.asExpr() = cie.getArgument(0)
    )
    or
    // File constructor
    exists(ClassInstanceExpr cie |
      cie.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File") |
      sink.asExpr() = cie.getAnArgument()
    )
    or
    // ResourceLoader.getResource()
    exists(MethodCall mc |
      mc.getMethod().hasName("getResource") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("org.springframework.core.io", "ResourceLoader") |
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

module ResourceTraversalFlow = TaintTracking::Global<ResourceTraversalConfig>;
import ResourceTraversalFlow::PathGraph

from ResourceTraversalFlow::PathNode source, ResourceTraversalFlow::PathNode sink
where ResourceTraversalFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Path traversal: user-controlled input $@ flows to resource loading operation.", source.getNode(), "user input"

/**
 * @name Path traversal in AbstractScmAccessor - user label to File constructor
 * @description User-controlled label/path flows to File constructor in AbstractScmAccessor without proper validation
 * @kind path-problem
 * @problem.severity error
 * @id java/scm-accessor-path-traversal
 * @tags security
 *       external/cwe/cwe-022
 */
import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module ScmAccessorConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // AbstractScmAccessor.java line 266 - new File() call
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File") and
      sink.asExpr() = ce.getAnArgument() and
      ce.getEnclosingCallable().getDeclaringType().hasName("AbstractScmAccessor")
    )
  }
}

module ScmAccessorFlow = TaintTracking::Global<ScmAccessorConfig>;
import ScmAccessorFlow::PathGraph

from ScmAccessorFlow::PathNode source, ScmAccessorFlow::PathNode sink
where ScmAccessorFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "User-controlled input flows to File constructor in AbstractScmAccessor from $@", source.getNode(), "HTTP request parameter"
